module RefModule(
  input clk,
  input reset,
  output reg [3:0] count
);reg [3:0] temp_count;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk or negedge reset or posedge dbg_halt) begin
  if (!reset) begin
    temp_count <= 4'b0000;
  end else begin
    temp_count <= temp_count + 4'b0001;
  end
end

assign count = temp_count;

endmodule
